    public partial class TicketStatusService : BaseService<TicketStatus>, ITicketStatusService
    {
        public TicketStatusService(IUnitOfWork uow) : base(uow)
        {

        }

        public override async Task Validation(TicketStatus item, Result<TicketStatus> executionResult)
        {
            if (await UOW.GetRepositoryAsync<TicketStatus>().HasRecordsAsync(x => x.Name == item.Name && x.Status == true && x.ID != item.ID))
            {
                executionResult.AddMessageItem(new MessageItem(nameof(TicketStatus.Name), "Name already exists"));
            }
        }
        public override async Task<TicketStatus> GetById(Guid id)
        {
            return await UOW.GetRepositoryAsync<TicketStatus>().SingleAsync(
                predicate: x => x.ID == id,
                orderBy: o => o.OrderByDescending(x => x.AddedAt));
        }

        public override async Task<IEnumerable<TicketStatus>> GetList(string orderBy)
        {
            return await UOW.GetRepositoryAsync<TicketStatus>().GetListAsync(orderBy, x => x.Status == true);
        }

        public override async Task<IPaginate<TicketStatus>> GetPaginate(BaseSearch search)
        {
            return await UOW.GetRepositoryAsync<TicketStatus>().GetPageListAsync(
                predicate: x => (string.IsNullOrEmpty(search.Name)
                     || x.Name.Contains(search.Name)),
                index: search.Page, size: search.Size, sortBy: search.SortBy ?? "Name", ascending: !search.IsDescend);
        }
